import json

# Load the business data (from var_functions.query_db:6)
business_data = [
    {"_id": "6859a000fe8b31cd7362e2ab", "business_id": "businessid_49", "description": "Located at 6901 Phelps Rd in Goleta, CA, this facility offers a nurturing environment for young learners, providing a range of services in Education, Elementary Schools, Child Care & Day Care, Local Services, Preschools, and Montessori Schools."},
    {"_id": "6859a000fe8b31cd7362e2ac", "business_id": "businessid_47", "description": "Located at 9916 Clayton Rd in St. Louis, MO, this establishment offers a wide range of services, including Hair Salons, Beauty & Spas, Hair Stylists, Skin Care, Blow Dry/Out Services, and Makeup Artists."},
    {"_id": "6859a000fe8b31cd7362e2ad", "business_id": "businessid_88", "description": "Located at 11655 W Executive Dr in Boise, ID, this facility offers enthusiasts a premier destination for Gun/Rifle Ranges, Active Life."},
    {"_id": "6859a000fe8b31cd7362e2ae", "business_id": "businessid_41", "description": "Located at 1615 Pasadena Ave S, Ste 430 in Saint Petersburg, FL, this facility offers a range of services in Internal Medicine, Doctors, Health & Medical."},
    {"_id": "6859a000fe8b31cd7362e2af", "business_id": "businessid_33", "description": "Located at 9655 E US Hwy 36, Unit H in Avon, IN, this establishment offers a range of services including Nail Salons, Hair Removal, Beauty & Spas, and Waxing."}
]

# Extract categories from descriptions
category_map = {}
for business in business_data:
    business_id = business['business_id']
    description = business['description']

    # Find the category list (it appears after "services in" or "services including")
    if "services in" in description:
        category_part = description.split("services in")[1].strip()
    elif "services including" in description:
        category_part = description.split("services including")[1].strip()
    else:
        category_part = description

    # Remove location info and trailing punctuation
    category_part = category_part.split(". Located at")[0] if ". Located at" in category_part else category_part
    category_part = category_part.rstrip(".")

    # Split by commas and "and"
    categories = []
    parts = category_part.split(',')
    for part in parts:
        part = part.strip()
        if ' and ' in part:
            subparts = part.split(' and ')
            for subpart in subparts:
                subpart = subpart.strip()
                if subpart:
                    categories.append(subpart)
        else:
            if part:
                categories.append(part)

    category_map[business_id] = categories

print("__RESULT__:")
print(json.dumps(category_map, indent=2))
"}

