# Function to extract categories from description
def extract_categories(description):
    """Extract business categories from description text"""
    description_lower = description.lower()

    # Look for category indicators
    if 'services in' in description_lower:
        # Extract after "services in"
        start = description_lower.find('services in') + len('services in')
        category_text = description[start:].strip()
    elif 'services including' in description_lower:
        start = description_lower.find('services including') + len('services including')
        category_text = description[start:].strip()
    elif 'premier destination for' in description_lower:
        start = description_lower.find('premier destination for') + len('premier destination for')
        category_text = description[start:].strip()
    else:
        # Try to find any comma-separated list that could be categories
        if ',' in description:
            # Look for patterns after common phrases
            phrases = ['services in', 'including', 'such as', 'offers', 'providing', 'destination for']
            for phrase in phrases:
                if phrase in description_lower:
                    start = description_lower.find(phrase) + len(phrase)
                    end = description.find('.', start)
                    if end == -1:
                        end = len(description)
                    category_text = description[start:end].strip()
                    break
            else:
                return []
        else:
            return []

    # Clean up the text
    category_text = category_text.rstrip('.')

    # Split by commas and "and"
    categories = []
    parts = category_text.split(',')
    for part in parts:
        part = part.strip()
        # Split by " and " if present
        if ' and ' in part:
